def gen(rng, size):
    n = max(1, min(size, 100000))
    arr = []
    for _ in range(n):
        r = rng.random()
        if r < 0.08:
            arr.append(0)
        else:
            v = rng.randint(1, 1000000000)
            if rng.random() < 0.5:
                v = -v
            arr.append(v)
    return [arr]

