class Solution:
    def getMaxLen(self, nums):
        n = len(nums)
        best = 0
        i = 0
        while i < n:
            if nums[i] == 0:
                i += 1
                continue
            j = i
            while j < n and nums[j] != 0:
                j += 1
            for a in range(i, j):
                neg_count = 0
                for b in range(a, j):
                    if nums[b] < 0:
                        neg_count += 1
                    if neg_count % 2 == 0:
                        length = b - a + 1
                        if length > best:
                            best = length
            i = j
        return best

