class Solution:
    def getMaxLen(self, nums):
        best = 0
        pos = 0
        neg = 0
        for x in nums:
            if x == 0:
                pos = 0
                neg = 0
                continue
            if x > 0:
                pos = pos + 1
                neg = neg + 1 if neg > 0 else 0
            else:
                new_pos = neg + 1 if neg > 0 else 0
                new_neg = pos + 1
                pos, neg = new_pos, new_neg
            if pos > best:
                best = pos
        return best

