var getMaxLen = function(nums) {
    let best = 0, pos = 0, neg = 0;
    for (const x of nums) {
        if (x === 0) {
            pos = 0;
            neg = 0;
            continue;
        }
        if (x > 0) {
            pos = pos + 1;
            neg = neg > 0 ? neg + 1 : 0;
        } else {
            const newPos = neg > 0 ? neg + 1 : 0;
            const newNeg = pos + 1;
            pos = newPos;
            neg = newNeg;
        }
        if (pos > best) best = pos;
    }
    return best;
};
